            ContentJson = """{"title":"Shipments Field Reference","groups":[{"heading":"Shipment Form Fields (Create Dialog — Sidebar)","items":[{"label":"Sales Order (required)","value":"Autocomplete dropdown. Select the Sales Order this shipment fulfills. Displays as 'OrderNumber — CustomerName (CustomerPO)'. This is the only required field on the sidebar. data-testid: shipment-so"},{"label":"Carrier","value":"Text input, optional. The shipping carrier name (e.g., 'UPS', 'FedEx', 'USPS', 'DHL', 'Freight'). Displayed in the table and detail view. data-testid: shipment-carrier"},{"label":"Tracking Number","value":"Text input, optional. The carrier-provided tracking number. When present, enables the Track button in the detail view to load tracking timeline. data-testid: shipment-tracking"},{"label":"Weight","value":"Number input, optional. Total shipment weight in pounds. Displayed in detail view with 'lbs' suffix. data-testid: shipment-weight"},{"label":"Shipping Cost","value":"Number input, optional. Total shipping cost in dollars. Displayed in detail view formatted as currency. data-testid: shipment-cost"},{"label":"Notes","value":"Textarea, optional. Free-form notes about the shipment (special handling instructions, delivery notes, etc.). 3 rows. data-testid: shipment-notes"}]},{"heading":"Line Item Fields (Create Dialog — Main Area)","items":[{"label":"Order Line (required)","value":"Autocomplete dropdown. Choose one of the selected Sales Order's open lines — there is no free part picker. Only lines with quantity still left to ship are shown; each displays the part/description and the remaining quantity. You must select a Sales Order first; otherwise the prompt is 'Select an order first', and if everything is already shipped it reads 'All lines shipped'. data-testid: shipment-line-so-line"},{"label":"Quantity (required)","value":"Number input. Prefills with the line's remaining-to-ship quantity and is capped at it — trying to exceed the remaining quantity is rejected. Must be greater than 0. data-testid: shipment-line-qty"},{"label":"Add button","value":"Adds the selected order line and quantity as a new line item. Disabled when the line form is invalid (no order line selected or quantity below the minimum)."},{"label":"Remove button (X)","value":"Removes a line item from the shipment. Each line in the table has a red X button to remove it."}]},{"heading":"Shipment Statuses","items":[{"label":"Pending (gray chip)","value":"Initial status. Shipment has been created but items are not yet packed. Can be marked shipped directly or moved to Packed first."},{"label":"Packed (blue/info chip)","value":"Items have been packed and the shipment is ready to leave the facility. Can be marked shipped from this status."},{"label":"Shipped (primary chip)","value":"Shipment has left the facility. Shipped date is recorded automatically. Can be marked delivered from this status."},{"label":"In Transit (yellow/warning chip)","value":"Carrier has the shipment and it is en route. Can be marked delivered from this status. Tracking timeline shows carrier updates."},{"label":"Delivered (green/success chip)","value":"Customer has received the shipment. Delivered date is recorded automatically. Terminal status — no further actions available."},{"label":"Cancelled (red/error chip)","value":"Shipment was cancelled before delivery. Record is preserved for audit. Terminal status — no further actions available."}]},{"heading":"Detail View Fields (Read-Only)","items":[{"label":"Shipment Number","value":"Auto-generated unique identifier. Displayed prominently at the top of the detail view with a shipping icon."},{"label":"Customer Name","value":"Pulled from the linked Sales Order. Shown as a subtitle under the shipment number."},{"label":"Sales Order","value":"Clickable entity link that opens the Sales Order detail dialog. Shows the SO number."},{"label":"Carrier","value":"Shown only if a carrier was entered. Text display."},{"label":"Tracking Number","value":"Shown only if entered. Displayed in monospace font for readability. Enables the Track button."},{"label":"Shipped Date","value":"Shown only after marking shipped. Formatted as MM/dd/yyyy."},{"label":"Delivered Date","value":"Shown only after marking delivered. Formatted as MM/dd/yyyy."},{"label":"Weight","value":"Shown only if entered. Displayed with 'lbs' suffix."},{"label":"Shipping Cost","value":"Shown only if entered. Formatted as currency (e.g., $25.00)."},{"label":"Linked Invoice","value":"Shown only if an invoice has been generated for this shipment. Clickable entity link to the invoice detail."},{"label":"Notes","value":"Shown only if notes were entered. Free-form text block."},{"label":"Line Items","value":"Table showing description and quantity for each line. Header shows count (e.g., 'Line Items (3)')."},{"label":"Created At / Updated At","value":"Timestamps at the bottom of the detail view. Formatted as MM/dd/yyyy."}]},{"heading":"Buttons and Actions","items":[{"label":"New Shipment (primary button, page header)","value":"Opens the create shipment dialog. data-testid: new-shipment-btn"},{"label":"Save / Create Shipment (dialog footer)","value":"Creates the shipment. Disabled when form is invalid, no lines exist, or save is in progress. Validation popover shows violations on hover. data-testid: shipment-save-btn"},{"label":"Cancel (dialog footer)","value":"Closes the create dialog without saving."},{"label":"Mark Shipped (detail view)","value":"Transitions status to Shipped and records the shipped date. Available when status is Pending or Packed. Shows a confirmation dialog before proceeding."},{"label":"Mark Delivered (detail view)","value":"Transitions status to Delivered and records the delivered date. Available when status is Shipped or In Transit. Shows a confirmation dialog before proceeding."},{"label":"Get Rates (detail view)","value":"Opens the shipping rates dialog to compare carrier rates. Available when status is Pending or Packed. Shows rates from configured carriers with service level, price, and estimated delivery."},{"label":"Track (detail view)","value":"Loads the tracking timeline for the shipment. Available when a tracking number exists and the timeline is not already displayed. Shows tracking events with location, status, and timestamp."},{"label":"Close Tracking (detail view)","value":"Collapses the tracking timeline panel."},{"label":"Row Click (table)","value":"Opens the shipment detail dialog for the clicked row. Shows all shipment information, line items, tracking, and available actions."}]},{"heading":"Validation Rules","items":[{"label":"Sales Order","value":"Required. Must select a valid Sales Order from the autocomplete dropdown."},{"label":"Line Items","value":"At least one line item is required. The Save button is disabled and a validation message appears if no lines are present."},{"label":"Order Line (per line)","value":"Required. Must select one of the linked Sales Order's open lines from the autocomplete — not a free part."},{"label":"Quantity (per line)","value":"Required. Must be greater than 0 and cannot exceed the line's remaining-to-ship quantity."},{"label":"Carrier, Tracking Number, Weight, Shipping Cost, Notes","value":"All optional. No format restrictions."},{"label":"Submit button popover","value":"When form is invalid or no lines exist, hovering over the Save button shows a validation popover listing all violations."}]},{"heading":"Table Columns","items":[{"label":"Shipment #","value":"Sortable. Width: 120px. Auto-generated shipment number displayed in monospace font."},{"label":"SO #","value":"Sortable. Width: 120px. The linked Sales Order number displayed in monospace font."},{"label":"Customer","value":"Sortable. Customer name from the linked Sales Order."},{"label":"Status","value":"Sortable, filterable (enum). Width: 120px. Color-coded chip: Pending (gray), Packed (blue), Shipped (primary), In Transit (yellow), Delivered (green), Cancelled (red)."},{"label":"Carrier","value":"Sortable. Width: 100px. Carrier name or '---' if not set."},{"label":"Tracking #","value":"Sortable. Width: 140px. Tracking number in monospace font or '---' if not set."},{"label":"Shipped Date","value":"Sortable. Width: 110px. Date type. Formatted as MM/dd/yyyy or '---' if not yet shipped."},{"label":"Created","value":"Sortable. Width: 110px. Date type. Record creation date formatted as MM/dd/yyyy."}]}]}"""
