            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"sh1","text":"A customer's Sales Order is ready to ship. What is the first step to record the outbound shipment in QB Engineer?","options":[{"id":"a","text":"Go to Sales Orders and click a Ship button on the order"},{"id":"b","text":"Navigate to Shipments, click New Shipment, select the Sales Order, add line items by choosing the order's open lines and quantities, then save","isCorrect":true},{"id":"c","text":"Go to Inventory and create a bin movement to remove the items from stock"},{"id":"d","text":"Create an Invoice first and the shipment is generated automatically"}],"explanation":"Shipments are created from the Shipments page. Click New Shipment, select the Sales Order from the autocomplete, then add line items by choosing from that order's open lines (there is no free part picker; quantity is capped at what remains to ship on each line), and save. The shipment starts in Pending status."},{"id":"sh2","text":"What is the correct order of shipment statuses from creation to completion?","options":[{"id":"a","text":"Draft → Packed → Shipped → Delivered"},{"id":"b","text":"Pending → Packed → Shipped → In Transit → Delivered","isCorrect":true},{"id":"c","text":"Open → Processing → Shipped → Closed"},{"id":"d","text":"Created → Ready → Out for Delivery → Complete"}],"explanation":"The shipment lifecycle is: Pending (created) → Packed (items ready) → Shipped (left facility) → In Transit (carrier has it) → Delivered (customer received). Not every shipment passes through all statuses — you can skip from Pending directly to Shipped."},{"id":"sh3","text":"You have a Sales Order with 100 units but the customer wants 50 shipped now and 50 later. How do you handle this?","options":[{"id":"a","text":"You cannot split shipments — the entire Sales Order must ship at once"},{"id":"b","text":"Create two separate shipments against the same Sales Order, each with 50 units","isCorrect":true},{"id":"c","text":"Edit the Sales Order to reduce it to 50, then create a second Sales Order for the remaining 50"},{"id":"d","text":"Ship all 100 and mark 50 as backordered in the notes"}],"explanation":"A single Sales Order can have multiple shipments (partial deliveries). Create the first shipment with 50 units, then later create a second shipment with the remaining 50 units — both linked to the same Sales Order."},{"id":"sh4","text":"A shipment is currently in Pending status. Which actions are available in the detail view?","options":[{"id":"a","text":"Only Mark Delivered"},{"id":"b","text":"Mark Shipped and Get Rates","isCorrect":true},{"id":"c","text":"Mark Shipped, Get Rates, Mark Delivered, and Track"},{"id":"d","text":"No actions — you must edit the shipment first"}],"explanation":"From Pending (or Packed) status, two actions are available: Mark Shipped (transitions to Shipped and records the date) and Get Rates (opens carrier rate comparison dialog). Mark Delivered is only available from Shipped or In Transit status. Track is available whenever a tracking number exists."},{"id":"sh5","text":"What is required to save a new shipment?","options":[{"id":"a","text":"Only a Sales Order selection"},{"id":"b","text":"A Sales Order selection and at least one line item drawn from that order's open lines","isCorrect":true},{"id":"c","text":"A Sales Order, carrier, and tracking number"},{"id":"d","text":"A Sales Order, line items, carrier, tracking number, and weight"}],"explanation":"Two things are required: a Sales Order must be selected (the only required sidebar field), and at least one line item must be added. Lines are drawn from the selected order's open lines (no free part picker), and each line's quantity is capped at what remains to ship. Carrier, tracking number, weight, shipping cost, and notes are all optional."},{"id":"sh6","text":"You want to compare shipping rates from different carriers before shipping. Where do you do this?","options":[{"id":"a","text":"Go to Admin → Shipping → Rate Calculator"},{"id":"b","text":"Open the shipment detail (click the row), then click Get Rates to open the rate comparison dialog","isCorrect":true},{"id":"c","text":"Navigate to the linked Sales Order and use its shipping tab"},{"id":"d","text":"Rates are not available in QB Engineer — you must check carrier websites separately"}],"explanation":"In the shipment detail view, click the Get Rates button (available when status is Pending or Packed). This opens a dialog showing rates from configured carriers with service level, price, and estimated delivery time. You can create a shipping label directly from this dialog."},{"id":"sh7","text":"A shipment has a tracking number entered. How do you view the tracking timeline?","options":[{"id":"a","text":"Go to the carrier's website and paste the tracking number"},{"id":"b","text":"Open the shipment detail and click the Track button to load the tracking timeline directly in QB Engineer","isCorrect":true},{"id":"c","text":"Tracking timelines are only available for shipments with carrier API integration enabled"},{"id":"d","text":"Navigate to Admin → Tracking to look up any tracking number"}],"explanation":"When a tracking number is present, a Track button appears in the shipment detail view. Click it to load the tracking timeline, which shows each tracking event with location, status, and timestamp — all within QB Engineer. Click the close button to collapse the timeline."},{"id":"sh8","text":"What happens when you click Mark Shipped on a shipment?","options":[{"id":"a","text":"The shipment is immediately deleted and an invoice is created"},{"id":"b","text":"A confirmation dialog appears, and if confirmed, the status changes to Shipped and the shipped date is recorded automatically","isCorrect":true},{"id":"c","text":"The status changes without confirmation and you must manually enter the shipped date"},{"id":"d","text":"An email is automatically sent to the customer with the tracking number"}],"explanation":"Clicking Mark Shipped opens a confirmation dialog. If you confirm, the status transitions to Shipped and the shipped date is automatically set to the current date. A success snackbar confirms the action. The customer is not automatically notified."},{"id":"sh9","text":"Where can you see which invoice is linked to a shipment?","options":[{"id":"a","text":"In the Sales Order detail under the Shipments tab"},{"id":"b","text":"In the shipment detail view — a Linked Invoice field appears with a clickable link to the invoice","isCorrect":true},{"id":"c","text":"Invoices and shipments are not linked in QB Engineer"},{"id":"d","text":"In the Reports module under Shipment-Invoice Mapping"}],"explanation":"The shipment detail view shows a Linked Invoice field when an invoice has been created for the shipment. The invoice number is a clickable entity link that opens the invoice detail dialog directly."},{"id":"sh10","text":"You need a printable document to include in a physical package. What does the shipment detail view give you?","options":[{"id":"a","text":"Print the shipment detail page using the browser's print function"},{"id":"b","text":"Download Ship Document (a versioned PDF with shipment number, customer info, shipping address, and line items with quantities), with a Regenerate Ship Document button alongside it","isCorrect":true},{"id":"c","text":"Documents are only available through the Sales Order detail"},{"id":"d","text":"Create a custom report in the Reports module filtered by shipment number"}],"explanation":"Once a tracking number exists, the shipment detail view shows a Download Ship Document button — a versioned PDF that includes the shipment number, customer details, shipping address, and a table of all line items with descriptions and quantities — plus a Regenerate Ship Document button to produce a fresh copy. These buttons only appear after a tracking number is present. (There is no separate 'packing slip' button reachable from the shipment.)"},{"id":"sh11","text":"The Shipments table shows '---' in the Tracking # column for a shipment. What does this mean?","options":[{"id":"a","text":"The tracking number has been redacted for security"},{"id":"b","text":"No tracking number has been entered for this shipment","isCorrect":true},{"id":"c","text":"The shipment is using a carrier that does not support tracking"},{"id":"d","text":"The tracking number will appear once the shipment status changes to Shipped"}],"explanation":"When no tracking number has been entered, the table displays '---' as a placeholder. The same applies to the Carrier and Shipped Date columns. Tracking numbers can be entered when creating the shipment, or added later via carrier label creation or manual edit."},{"id":"sh12","text":"A shipment is in Shipped status. Which action button is available in the detail view?","options":[{"id":"a","text":"Mark Shipped and Get Rates"},{"id":"b","text":"Mark Delivered (and Track, if a tracking number exists)","isCorrect":true},{"id":"c","text":"Cancel Shipment and Create Invoice"},{"id":"d","text":"No actions — Shipped is a terminal status"}],"explanation":"From Shipped (or In Transit) status, the Mark Delivered button is available. If a tracking number exists and the tracking timeline hasn't been loaded yet, the Track button also appears. Mark Shipped and Get Rates are only available from Pending or Packed status."}]}"""
